MERGE INTO CONSULTAS FIN USING (SELECT '800640ANALISISCARTERAXTERCERO' INFORME ,TO_CLOB(q'[SELECT  
   DETALLE_COMPROBANTE_CNT.TERCERO,  
   TERCERO.NOMBRE,  
   TERCERO.DIRECCION, 
   TERCERO.CIUDAD,
   TERCERO.TELEFONOS,
   SUM(CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) <= 0 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END) AS SALDO_CORRIENTE,
   SUM(CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 1 AND 30 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END) AS DIAS1_30, 
   SUM(CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 31 AND 60 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END) AS DIAS31_60, 
   SUM(CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 61 AND 90 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END) AS DIAS61_90, 
   SUM(CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 91 AND 120 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END) AS DIAS91_120,
   SUM(CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 121 AND 150 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END) AS DIAS121_150,
   SUM(CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 151 AND 180 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END) AS DIAS151_180,
   SUM(CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 181 AND 270 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END) AS DIAS181_270,
   SUM(CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 271 AND 360 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END) AS DIAS271_360,
   SUM(CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) >361 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END) AS MAS_361DIAS,

   SUM((CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 1 AND 30 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)+
       (CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 31 AND 60 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)+
       (CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 61 AND 90 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)+
       (CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/]') || TO_CLOB(q'[YYYY')) BETWEEN 91 AND 120 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)+
       (CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 121 AND 150 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)+
       (CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 151 AND 180 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)+  
       (CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 181 AND 270 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)+
       (CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 271 AND 360 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)+   
       (CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) >361 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)) AS TOTAL_VENCIDO,
       
        SUM(CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) <= 0 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END) 
      + SUM((CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 1 AND 30 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)+
       (CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 31 AND 60 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)+
       (CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 61 AND 90 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)+
       (CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 91 AND 120 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)+
       (CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 121 AND 150 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)+
       (CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 151 AND 180 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)+  
       (CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 181 AND 270 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)+
       (CASE WHEN TO_DATE('s$fechaCorte$s','DD/MM/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) BETWEEN 271 AND 360 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)+   
       (CASE WHEN TO_DATE('s$fechaCorte$s','DD/M]') || TO_CLOB(q'[M/YYYY')-TO_DATE(TO_CHAR(COMPROBANTE_CNT.s$porVencimiento$s,'DD/MM/YYYY')) >361 THEN VALOR_DEBITO-DEBITO_AFECTADO-ABONOINICIAL ELSE 0 END)) AS SALDO_TOTAL
 FROM DETALLE_COMPROBANTE_CNT 
   INNER JOIN PLAN_CONTABLE 
 V_PLAN_CONTABLE 
      ON DETALLE_COMPROBANTE_CNT.COMPANIA = V_PLAN_CONTABLE.COMPANIA 
     AND DETALLE_COMPROBANTE_CNT.ANO      = V_PLAN_CONTABLE.ANO 
     AND DETALLE_COMPROBANTE_CNT.CUENTA   = V_PLAN_CONTABLE.CODIGO  

   INNER JOIN COMPROBANTE_CNT  
      ON DETALLE_COMPROBANTE_CNT.COMPANIA    = COMPROBANTE_CNT.COMPANIA    
     AND DETALLE_COMPROBANTE_CNT.TIPO_CPTE   = COMPROBANTE_CNT.TIPO 
     AND DETALLE_COMPROBANTE_CNT.ANO         = COMPROBANTE_CNT.ANO 
     AND DETALLE_COMPROBANTE_CNT.COMPROBANTE = COMPROBANTE_CNT.NUMERO 
   INNER JOIN TERCERO 
      ON DETALLE_COMPROBANTE_CNT.COMPANIA = TERCERO.COMPANIA  
     AND DETALLE_COMPROBANTE_CNT.TERCERO  = TERCERO.NIT  
     AND DETALLE_COMPROBANTE_CNT.SUCURSAL = TERCERO.SUCURSAL 
   INNER JOIN TIPO_COMPROBANTE  
      ON DETALLE_COMPROBANTE_CNT.COMPANIA  = TIPO_COMPROBANTE.COMPANIA 
     AND DETALLE_COMPROBANTE_CNT.TIPO_CPTE = TIPO_COMPROBANTE.CODIGO 
 WHERE DETALLE_COMPROBANTE_CNT.COMPANIA = s$compania$s  
   AND VALOR_DEBITO-(DETALLE_COMPROBANTE_CNT.DEBITO_AFECTADO+DETALLE_COMPROBANTE_CNT.CREDITO_AFECTADO)-ABONOINICIAL >0
   AND DETALLE_COMPROBANTE_CNT.FECHA   <= TO_DATE('s$fechaCorte$s','DD/MM/YYYY') 
   AND DETALLE_COMPROBANTE_CNT.CUENTA BETWEEN 's$cuentaInicial$s' AND 's$cuentaFinal$s'
   AND V_PLAN_CONTABLE.CLASECUENTA      = 'C' 
   AND TIPO_COMPROBANTE.CLASE_CONTABLE  = 'V' 
   AND TERCERO.NIT               BETWEEN 's$terceroInicial$s' AND 's$terceroFinal$s'
GROUP BY  
   DETALLE_COMPROBANTE_CNT.TERCERO,  
   TERCERO.NOMBRE,  
   TERCERO.DIRECCION, 
   TERCERO.CIUDAD,
   TERCERO.TELEFONOS]') CONSULTA, 1 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, 'MROSERO' CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);